const express = require('express');
const redis = require('redis');
const twilio = require('twilio');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

const redisClient = redis.createClient();
const twilioClient = twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN);

// Rate limiting for code verification
const verifyLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 10,
  message: 'Too many verification attempts, please try again later'
});

// Rate limiting for code generation
const codeLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 5,
  message: 'Too many code requests, please try again later'
});

// Generate 6-digit code
function generateCode() {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

// Store code in Redis with 10-minute expiration
async function storeCode(phone, code) {
  try {
    await redisClient.setex(`mfa:${phone}`, 600, code); // 10 minutes
    return true;
  } catch (error) {
    console.error('Redis error:', error);
    return false;
  }
}

// Get stored code
async function getStoredCode(phone) {
  try {
    return await redisClient.get(`mfa:${phone}`);
  } catch (error) {
    console.error('Redis error:', error);
    return null;
  }
}

// Send SMS via Twilio
async function sendSMS(phone, code) {
  try {
    await twilioClient.messages.create({
      body: `Your verification code is: ${code}`,
      from: process.env.TWILIO_PHONE_NUMBER,
      to: phone
    });
    return true;
  } catch (error) {
    console.error('Twilio error:', error);
    return false;
  }
}

// Generate and send code endpoint
app.post('/mfa/generate', codeLimiter, async (req, res) => {
  const { phone } = req.body;
  
  if (!phone) {
    return res.status(400).json({ error: 'Phone number required' });
  }
  
  const code = generateCode();
  const stored = await storeCode(phone, code);
  
  if (!stored) {
    return res.status(500).json({ error: 'Failed to generate code' });
  }
  
  const sent = await sendSMS(phone, code);
  
  if (!sent) {
    return res.status(500).json({ error: 'Failed to send SMS' });
  }
  
  res.json({ message: 'Verification code sent' });
});

// Verify code endpoint
app.post('/mfa/verify', verifyLimiter, async (req, res) => {
  const { phone, code } = req.body;
  
  if (!phone || !code) {
    return res.status(400).json({ error: 'Phone and code required' });
  }
  
  const storedCode = await getStoredCode(phone);
  
  if (!storedCode) {
    return res.status(400).json({ error: 'Invalid or expired code' });
  }
  
  if (storedCode === code) {
    // Clear the code after successful verification
    await redisClient.del(`mfa:${phone}`);
    return res.json({ message: 'Verification successful' });
  } else {
    return res.status(400).json({ error: 'Invalid code' });
  }
});

module.exports = app;